// --- 5. Main App Component ---
export default function App() {
  const [state, dispatch] = useReducer(
    authReducer,
    {
      isLoading: true,
      isSignout: false,
      userToken: null,
      user: null,
    }
  );

  useEffect(() => {
    // Fetch the token and user from storage then navigate to our appropriate route
    const bootstrapAsync = async () => {
      let userToken;
      let userData;

      try {
        userToken = await AsyncStorage.getItem('userToken');
        const userJson = await AsyncStorage.getItem('userData');
        userData = userJson ? JSON.parse(userJson) : null;
      } catch (e) {
        // Restoring token failed
        console.error('Failed to restore token or user data', e);
      }

      // After restoring token, we may need to validate it in production apps
      // For this MVP, we assume a stored token is valid.
      dispatch({ type: 'RESTORE_TOKEN', token: userToken, user: userData });
    };

    bootstrapAsync();
  }, []);

  const authContext = useMemo(
    () => ({
      signIn: async (username, password) => {
        dispatch({ type: 'LOADING', isLoading: true });
        try {
          const { user, token } = await mockApiService.signIn(username, password);
          await AsyncStorage.setItem('userToken', token);
          await AsyncStorage.setItem('userData', JSON.stringify(user));
          dispatch({ type: 'SIGN_IN', token, user });
        } finally {
          dispatch({ type: 'LOADING', isLoading: false });
        }
      },
      signOut: async () => {
        await AsyncStorage.removeItem('userToken');
        await AsyncStorage.removeItem('userData');
        dispatch({ type: 'SIGN_OUT' });
      },
      signUp: async (username, email, password) => {
        dispatch({ type: 'LOADING', isLoading: true });
        try {
          const { user, token } = await mockApiService.signUp(username, email, password);
          await AsyncStorage.setItem('userToken', token);
          await AsyncStorage.setItem('userData', JSON.stringify(user));
          dispatch({ type: 'SIGN_IN', token, user });
        } finally {
          dispatch({ type: 'LOADING', isLoading: false });
        }
      },
      user: state.user, // Expose user data to context consumers
    }),
    [state.user] // Re-memoize if user changes
  );

  return (
    <AuthContext.Provider value={authContext}>
      <NavigationContainer>
        <StatusBar barStyle="dark-content" />
        {state.isLoading ? (
          <LoadingScreen />
        ) : state.userToken == null ? (
          <AuthStackNavigator />
        ) : (
          <AppStackNavigator />
        )}
      </NavigationContainer>
    </AuthContext.Provider>
  );
}

